+        assert_eq!(ptrs[0].key.objectid, 256);
+        assert_eq!(ptrs[0].blockptr, 0x4000);
+        assert_eq!(ptrs[0].generation, 10);
+        assert_eq!(ptrs[1].key.objectid, 512);
+        assert_eq!(ptrs[1].blockptr, 0x8000);
+    }
